    for (int row = 0; row < nRows; row++) {
        permutation[row] = row;
    }
    parity = 1;
    // Loop over columns
    for (int col = 0; col < nCols; col++) {
        BigDecimal sum = ZERO;
        // upper
        for (int row = 0; row < col; row++) {
            final BigDecimal[] luRow = lu[row];
            sum = luRow[col];
            for (int i = 0; i < row; i++) {
                sum = sum.subtract(luRow[i].multiply(lu[i][col]));
            }
            luRow[col] = sum;
        }
        // lower
        // permutation row
        int max = col;
        BigDecimal largest = ZERO;
        for (int row = col; row < nRows; row++) {
            final BigDecimal[] luRow = lu[row];
            sum = luRow[col];
            for (int i = 0; i < col; i++) {
                sum = sum.subtract(luRow[i].multiply(lu[i][col]));
            }
            luRow[col] = sum;
            // maintain best permutation choice
            if (sum.abs().compareTo(largest) == 1) {
                largest = sum.abs();
                max = row;
            }
        }
        // Singularity check
        if (lu[max][col].abs().compareTo(TOO_SMALL) <= 0) {
            lu = null;
            throw new SingularMatrixException();
        }
        // Pivot if necessary
        if (max != col) {
            BigDecimal tmp = ZERO;
            for (int i = 0; i < nCols; i++) {
                tmp = lu[max][i];
                lu[max][i] = lu[col][i];
                lu[col][i] = tmp;
            }
            int temp = permutation[max];
            permutation[max] = permutation[col];
            permutation[col] = temp;
            parity = -parity;
        }
        // Divide the lower elements by the "winning" diagonal elt.
        final BigDecimal luDiag = lu[col][col];
        for (int row = col + 1; row < nRows; row++) {
            final BigDecimal[] luRow = lu[row];
            luRow[col] = luRow[col].divide(luDiag, scale, roundingMode);
        }
    }
}

